s:script.c:code:
import com.evolveum.midpoint.xml.ns._public.common.common_3.UserType;

def user = input;
def uoid = user.getOid();
def uname = user.getName()?.getOrig();

// Filtro: actuar solo si emailAddress ~ ^\d+@upeu\.edu\.pe$
def email = user.getEmailAddress();
if (email == null || email.trim().isEmpty()) return;
def emailStr = email.toString().trim();
if (!emailStr.matches('^\\d+@upeu\\.edu\\.pe$')) return;

// DELETE emailAddress: replaceRealValues(emptyList()) genera un REPLACE vacío
// que sí borra el valor en DB (a diferencia de .replace() sin argumento que es no-op).
// raw() — sin clockwork, sin proyección Entra/LDAP/Koha.
try {
    def delta = midpoint.prismContext.deltaFor(UserType.class)
        .item(UserType.F_EMAIL_ADDRESS).replaceRealValues(java.util.Collections.emptyList())
        .asObjectDelta(uoid);
    def meoClass = Class.forName('com.evolveum.midpoint.model.api.ModelExecuteOptions');
    def opts = meoClass.getMethod('create').invoke(null);
    opts = opts.getClass().getMethod('raw').invoke(opts);
    midpoint.executeChanges([delta] as java.util.Collection, opts);
    log.info('EMAIL-CLEANUP r10 OK: {} ({}) was {}', uname, uoid, emailStr);
} catch (Exception e) {
    log.warn('EMAIL-CLEANUP r10 ERROR: {} ({}): {}', uname, uoid, e.message);
}
